function beAssembleBackendZipInputs() {
    function getExtension(filePath) {
      const fileName = String(filePath || '').split('/').pop() || '';
      if (fileName === 'pom.xml') return 'xml';
      if (fileName === '.gitignore') return 'gitignore';
      const match = fileName.match(/\.([A-Za-z0-9]+)$/);
      return match ? match[1].toLowerCase() : 'txt';
    }
    function getMimeType(filePath) {
      const ext = getExtension(filePath);
      const mimeByExtension = {
        java: 'text/x-java-source',
        xml: 'application/xml',
        yaml: 'text/yaml',
        yml: 'text/yaml',
        json: 'application/json',
        properties: 'text/plain',
        md: 'text/markdown',
        txt: 'text/plain',
        sql: 'application/sql',
        csv: 'text/csv',
        gitignore: 'text/plain',
      };
      return mimeByExtension[ext] || 'text/plain';
    }
    function isIntentionallyEmptyFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      return lower.endsWith('/.gitkeep') || lower.endsWith('/.keep') || lower.endsWith('/.placeholder');
    }
    function normalizeContent(contentValue) {
      if (typeof contentValue === 'string') {
        return contentValue;
      }
      if (contentValue === null || contentValue === undefined) {
        return '';
      }
      if (typeof contentValue === 'object') {
        return JSON.stringify(contentValue, null, 2);
      }
      return String(contentValue);
    }
    const item = $input.first();
    if (!item) {
      throw new Error('No frontend generation state available for ZIP assembly.');
    }
    const json = item.json || {};
    const generatedFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const remainingFiles = Array.isArray(json.remainingFiles) ? json.remainingFiles : [];
    if (remainingFiles.length > 0) {
      throw new Error('Cannot assemble frontend ZIP while files are still remaining.');
    }
    if (!generatedFiles.length) {
      throw new Error('No generated frontend files available to assemble ZIP.');
    }
    const binary = {};
    const manifest = [];
    generatedFiles.forEach((file, index) => {
      const filePath = String(file?.path || '').trim();
      const content = normalizeContent(file?.content);
      if (!filePath.startsWith('frontend/')) {
        throw new Error(`Generated frontend file path must start with "frontend/": ${filePath || '<empty>'}`);
      }
      // Empty files are allowed and must still be included in the assembled ZIP.
      const key = `file_${index}`;
      binary[key] = {
        data: Buffer.from(content, 'utf8').toString('base64'),
        mimeType: getMimeType(filePath),
        fileExtension: getExtension(filePath),
        fileName: filePath,
      };
      manifest.push({ path: filePath });
    });
    return [{
      json: {
        frontendRoot: 'frontend',
        fileCount: manifest.length,
        files: manifest,
        zipBinaryFields: Object.keys(binary).join(','),
      },
      binary,
    }];
  }
return beAssembleBackendZipInputs();

async function beAssembleFrontendZipInputs() {
    function getExtension(filePath) {
      const fileName = String(filePath || '').split('/').pop() || '';
      if (fileName === 'pom.xml') return 'xml';
      if (fileName === '.gitignore') return 'gitignore';
      const match = fileName.match(/\.([A-Za-z0-9]+)$/);
      return match ? match[1].toLowerCase() : 'txt';
    }
    function getMimeType(filePath) {
      const ext = getExtension(filePath);
      const mimeByExtension = {
        java: 'text/x-java-source',
        xml: 'application/xml',
        yaml: 'text/yaml',
        yml: 'text/yaml',
        json: 'application/json',
        properties: 'text/plain',
        md: 'text/markdown',
        txt: 'text/plain',
        sql: 'application/sql',
        csv: 'text/csv',
        gitignore: 'text/plain',
      };
      return mimeByExtension[ext] || 'text/plain';
    }
    function isIntentionallyEmptyFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      return lower.endsWith('/.gitkeep') || lower.endsWith('/.keep') || lower.endsWith('/.placeholder');
    }
    function normalizeContent(contentValue) {
      if (typeof contentValue === 'string') {
        return contentValue;
      }
      if (contentValue === null || contentValue === undefined) {
        return '';
      }
      if (typeof contentValue === 'object') {
        return JSON.stringify(contentValue, null, 2);
      }
      return String(contentValue);
    }
    function normalizeFrontendPath(rawPath, frontendRoot, rawDirectory) {
      const normalizedRoot = String(frontendRoot || 'frontend').replace(/\\/g, '/').trim().replace(/\/+$/, '') || 'frontend';
      const directory = String(rawDirectory ?? '').replace(/\\/g, '/').trim().replace(/^\.\//, '').replace(/\/+$/, '');
      const fileName = String(rawPath ?? '').replace(/\\/g, '/').trim().replace(/^\.\//, '');
      const combined = [directory, fileName]
        .filter(Boolean)
        .join('/')
        .replace(/\/+/g, '/')
        .replace(/^\.\//, '')
        .replace(/\/+/g, '/');
      if (!combined) return '';
      if (combined === normalizedRoot || combined === normalizedRoot + '.zip') return '';
      if (combined.startsWith(normalizedRoot + '/')) return combined;
      return normalizedRoot + '/' + combined.replace(/^\/+/, '');
    }
    async function readBinaryText(propertyName, binaryEntry) {
      try {
        if (typeof this?.helpers?.getBinaryDataBuffer === 'function') {
          const buffer = await this.helpers.getBinaryDataBuffer(0, propertyName);
          if (buffer) return buffer.toString('utf8');
        }
      } catch {}
      try {
        const raw = String(binaryEntry?.data ?? '');
        return raw && raw !== 'filesystem-v2' ? Buffer.from(raw, 'base64').toString('utf8') : '';
      } catch {
        return '';
      }
    }
    async function collectGeneratedFilesFromBinary(binary, frontendRoot) {
      const byPath = new Map();
      for (const [propertyName, entry] of Object.entries(binary || {})) {
        if (!/^current_/i.test(propertyName)) continue;
        const filePath = normalizeFrontendPath(entry?.fileName, frontendRoot, entry?.directory);
        if (!filePath || filePath.endsWith('.zip')) continue;
        byPath.set(filePath, { path: filePath, content: await readBinaryText.call(this, propertyName, entry) });
      }
      return Array.from(byPath.values()).sort((a, b) => a.path.localeCompare(b.path));
    }
    const item = $input.first();
    if (!item) {
      throw new Error('No frontend generation state available for ZIP assembly.');
    }
    const json = item.json || {};
    const frontendRoot = String(json.frontendRoot ?? 'frontend').trim() || 'frontend';
    const remainingFiles = Array.isArray(json.remainingFiles) ? json.remainingFiles : [];
    if (remainingFiles.length > 0) {
      throw new Error('Cannot assemble frontend ZIP while files are still remaining.');
    }
    const generatedFilesInput = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const generatedFiles = generatedFilesInput.length
      ? generatedFilesInput
      : await collectGeneratedFilesFromBinary.call(this, item.binary || {}, frontendRoot);
    if (!generatedFiles.length) {
      throw new Error('No generated frontend files available to assemble ZIP.');
    }
    const byPath = new Map();
    for (const file of generatedFiles) {
      const path = String(file?.path || '').trim();
      if (!path) continue;
      if (!byPath.has(path)) byPath.set(path, { path, content: file.content });
    }
    const binary = {};
    const manifest = [];
    Array.from(byPath.values()).forEach((file, index) => {
      const filePath = String(file?.path || '').trim();
      const content = normalizeContent(file?.content);
      if (!filePath.startsWith('frontend/')) {
        throw new Error(`Generated frontend file path must start with "frontend/": ${filePath || '<empty>'}`);
      }
      // Empty files are allowed and must still be included in the assembled ZIP.
      const key = `file_${index}`;
      binary[key] = {
        data: Buffer.from(content, 'utf8').toString('base64'),
        mimeType: getMimeType(filePath),
        fileExtension: getExtension(filePath),
        fileName: filePath,
      };
      manifest.push({ path: filePath });
    });
    return [{
      json: {
        frontendRoot: 'frontend',
        fileCount: manifest.length,
        files: manifest,
        zipBinaryFields: Object.keys(binary).join(','),
      },
      binary,
    }];
  }
return beAssembleFrontendZipInputs();

function feBuildChunkPrompt() {
  const MAX_MEMORY_ITEMS = 4;

  function compactJson(value) {
    return JSON.stringify(value);
  }

  function trimImplementationMemory(generatedImplementationIndex, recentImplementationSummaries) {
    const seen = new Set();
    const selected = [];

    for (const collection of [recentImplementationSummaries || [], generatedImplementationIndex || []]) {
      for (const entry of collection) {
        if (!entry || typeof entry !== 'object') continue;
        const path = String(entry.path || '').trim();
        if (!path || seen.has(path)) continue;
        seen.add(path);
        selected.push(entry);
        if (selected.length >= MAX_MEMORY_ITEMS) {
          return selected;
        }
      }
    }

    return selected;
  }

  return $input.all().map((item) => {
    const json = item.json || {};
    const requirementsText = String(json.requirementsText || '').trim();
    const openapiText = String(json.openapiText || '').trim();
    const designText = String(json.designText || '').trim();
    if (!requirementsText) throw new Error('Missing requirements text for frontend generation.');
    if (!openapiText) throw new Error('Missing OpenAPI text for frontend generation.');
    if (!designText) throw new Error('Missing design text for frontend generation.');

    const batchSize = Math.max(1, Number(json.batchSize || 15));
    const currentBatchFiles = Array.isArray(json.currentBatchFiles) && json.currentBatchFiles.length
      ? json.currentBatchFiles.slice(0, batchSize)
      : (Array.isArray(json.remainingFiles) ? json.remainingFiles.slice(0, batchSize) : []);

    if (!currentBatchFiles.length) {
      throw new Error('No current batch files available for frontend generation.');
    }

    const allPlannedFiles = Array.isArray(json.allPlannedFiles) && json.allPlannedFiles.length
      ? json.allPlannedFiles
      : currentBatchFiles;
    const allPlannedPaths = allPlannedFiles
      .map((file) => String(file?.path || '').trim())
      .filter(Boolean);
    const batchPaths = currentBatchFiles
      .map((file) => String(file?.path || '').trim())
      .filter(Boolean);

    const implementationMemory = trimImplementationMemory(
      Array.isArray(json.generatedImplementationIndex) ? json.generatedImplementationIndex : [],
      Array.isArray(json.recentImplementationSummaries) ? json.recentImplementationSummaries : [],
    );

    const userPrompt = [
      'REQ',
      requirementsText,
      'API',
      openapiText,
      'DESIGN',
      designText,
      'PLAN',
      compactJson(allPlannedPaths),
      'BATCH',
      compactJson(batchPaths),
      'STATE',
      compactJson({
        i: json.iteration,
        g: json.generatedFileCountTotal,
        r: json.remainingFileCount,
        t: allPlannedPaths.length,
        b: batchSize,
        c: currentBatchFiles.length,
      }),
      implementationMemory.length ? 'MEMORY\n' + compactJson(implementationMemory) : '',
      'RULES',
      [
        'Generate only BATCH paths.',
        'PLAN is the full allowed frontend path set.',
        'Requirements define frontend features and business behavior.',
        'DESIGN defines screens, dialogs, navigation, layout intent, and component structure.',
        'OpenAPI is absolute truth for API requests, response fields, methods, auth-related contracts, and data shapes exchanged with the backend.',
        'Do not add or rewrite API path prefixes.',
        'Do not reference files or types outside BATCH, MEMORY, or PLAN.',
        'Reuse existing naming and generated types consistently.',
        'Return only valid JSON with a top-level files array.',
      ].join('\n'),
    ].filter(Boolean).join('\n');

    return {
      json: {
        ...json,
        batchSize,
        allPlannedFiles,
        currentBatchFiles,
        currentBatchFileCount: currentBatchFiles.length,
        userPrompt,
        requirementsPromptLength: requirementsText.length,
        openapiPromptLength: openapiText.length,
        designPromptLength: designText.length,
        implementationMemoryLength: compactJson(implementationMemory).length,
        fullPromptLength: userPrompt.length,
      },
      binary: item.binary ?? {},
    };
  });
}

return feBuildChunkPrompt();

async function feBuildPrompt() {
  const items = $input.all();
  if (!items.length) {
    throw new Error('Frontend structure prompt builder received no input.');
  }

  async function readBinaryText(itemIndex, propertyName, fallbackFileName) {
    const item = items[itemIndex];
    const binary = item.binary?.[propertyName];
    if (!binary) return null;

    const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, propertyName);
    return {
      fileName: binary.fileName || fallbackFileName,
      text: buffer.toString('utf8'),
    };
  }

  let requirements = null;
  let openapi = null;
  let design = null;

  for (let itemIndex = 0; itemIndex < items.length; itemIndex += 1) {
    if (!requirements) {
      requirements = await readBinaryText.call(this, itemIndex, 'requirements', 'requirements-compact.txt');
    }
    if (!openapi) {
      openapi = await readBinaryText.call(this, itemIndex, 'openapiSpec', 'openapi-compact.json');
    }
    if (!design) {
      design = await readBinaryText.call(this, itemIndex, 'designSpec', 'design-compact.json');
    }
  }

  if (!requirements) {
    throw new Error('Missing compact requirements binary for frontend structure generation.');
  }
  if (!openapi) {
    throw new Error('Missing compact openapiSpec binary for frontend structure generation.');
  }
  if (!design) {
    throw new Error('Missing compact designSpec binary for frontend structure generation.');
  }

  const requirementsText = String(requirements.text || '').trim();
  const openapiText = String(openapi.text || '').trim();
  const designText = String(design.text || '').trim();
  if (!requirementsText) {
    throw new Error('Requirements text is empty for frontend structure generation.');
  }
  if (!openapiText) {
    throw new Error('OpenAPI text is empty for frontend structure generation.');
  }
  if (!designText) {
    throw new Error('Design text is empty for frontend structure generation.');
  }

  const userPrompt = [
    'REQ',
    requirementsText,
    'API',
    openapiText,
    'DESIGN',
    designText,
  ].join('\n');

  return [{
    json: {
      requirementsFile: requirements.fileName,
      requirementsText,
      requirementsPromptLength: requirementsText.length,
      openapiFile: openapi.fileName || 'openapi-compact.json',
      openapiText,
      openapiPromptLength: openapiText.length,
      designFile: design.fileName || 'design-compact.json',
      designText,
      designPromptLength: designText.length,
      userPrompt,
      fullPromptLength: userPrompt.length,
    },
    binary: items[0].binary ?? {},
  }];
}

return await feBuildPrompt.call(this);

function feBuildRefinementChunkPrompt() {
  const MAX_MEMORY_ITEMS = 6;
  const ATTACHMENT_CHAR_LIMIT = 12000;
  const ATTACHMENT_FILE_CHAR_LIMIT = 3000;
  function compactJson(value) { return JSON.stringify(value); }
  function normalizeFiles(value) {
    const files = Array.isArray(value) ? value : [];
    return files.map((entry) => {
      if (typeof entry === 'string') return { path: entry.trim() };
      if (entry && typeof entry === 'object') return { path: String(entry.path ?? '').trim() };
      return { path: '' };
    }).filter((entry) => entry.path);
  }
  function decodeText(binaryEntry) {
    try {
      const raw = String(binaryEntry?.data ?? '');
      return raw ? Buffer.from(raw, 'base64').toString('utf8') : '';
    } catch {
      return '';
    }
  }
  function looksTextLike(binaryEntry, key) {
    const mime = String(binaryEntry?.mimeType ?? '').toLowerCase();
    const extRaw = String(binaryEntry?.fileExtension ?? '').toLowerCase();
    const ext = extRaw.startsWith('.') ? extRaw.slice(1) : extRaw;
    const textExt = new Set(['txt','md','markdown','json','yaml','yml','csv','tsv','xml','html','htm','js','ts','py','java','sql','log','ini','cfg']);
    if (mime.startsWith('text/')) return true;
    if (mime.includes('json') || mime.includes('xml') || mime.includes('yaml')) return true;
    if (textExt.has(ext)) return true;
    const keyLower = String(key ?? '').toLowerCase();
    return keyLower.endsWith('.txt') || keyLower.endsWith('.md') || keyLower.endsWith('.json');
  }
  function splitTokens(value) {
    const text = String(value || '').replace(/([a-z0-9])([A-Z])/g, '$1 $2').replace(/[^A-Za-z0-9]+/g, ' ').toLowerCase();
    return Array.from(new Set(text.split(/\s+/).filter((token) => token.length > 1)));
  }
  function detectLanguage(filePath) {
    const lower = String(filePath || '').toLowerCase();
    if (lower.endsWith('.java')) return 'java';
    if (lower.endsWith('.kt')) return 'kotlin';
    if (lower.endsWith('.py')) return 'python';
    if (lower.endsWith('.ts')) return 'typescript';
    if (lower.endsWith('.tsx')) return 'tsx';
    if (lower.endsWith('.js')) return 'javascript';
    if (lower.endsWith('.jsx')) return 'jsx';
    if (lower.endsWith('.cs')) return 'csharp';
    if (lower.endsWith('.go')) return 'go';
    if (lower.endsWith('.rb')) return 'ruby';
    if (lower.endsWith('.php')) return 'php';
    return 'other';
  }
  function isImplementationFile(filePath) {
    const lower = String(filePath || '').toLowerCase();
    if (!lower.startsWith('frontend/')) return false;
    if (lower.includes('/src/test/') || lower.includes('/tests/') || lower.includes('/test/')) return false;
    if (lower.includes('/resources/') || lower.includes('/db/') || lower.includes('/docs/') || lower.includes('/helm/')) return false;
    if (lower.endsWith('.md') || lower.endsWith('.txt') || lower.endsWith('.yaml') || lower.endsWith('.yml') || lower.endsWith('.xml') || lower.endsWith('.properties') || lower.endsWith('.sql') || lower.endsWith('.json') || lower.endsWith('.csv')) return false;
    return new Set(['java', 'kotlin', 'python', 'typescript', 'tsx', 'javascript', 'jsx', 'csharp', 'go', 'ruby', 'php']).has(detectLanguage(filePath));
  }

  function summarizeFile(file) {
    const filePath = String(file?.path || '').trim();
    const content = String(file?.content || '');
    const language = detectLanguage(filePath);
    const imports = [];
    for (const regex of [/^[ \t]*import\s+([^;\n]+)[;\n]?/gm, /^[ \t]*using\s+([^;\n]+);/gm, /^[ \t]*from\s+([^\n]+)\s+import\s+([^\n]+)/gm, /^[ \t]*require\(['"]([^'"]+)['"]\)/gm]) {
      let match;
      while ((match = regex.exec(content)) !== null && imports.length < 20) imports.push(match.slice(1).filter(Boolean).join(' ').trim());
      regex.lastIndex = 0;
    }
    const types = [];
    let match;
    const typeRegex = /^[ \t]*(?:export\s+)?(?:public\s+|private\s+|protected\s+|internal\s+)?(?:abstract\s+|final\s+|sealed\s+)?(class|interface|enum|record|type|struct)\s+([A-Za-z0-9_]+)/gm;
    while ((match = typeRegex.exec(content)) !== null && types.length < 12) types.push({ kind: match[1], name: match[2] });
    typeRegex.lastIndex = 0;
    const functions = [];
    const fnRegex = /^[ \t]*(?:export\s+)?(?:async\s+)?(?:function|def|func|fn)\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm;
    while ((match = fnRegex.exec(content)) !== null && functions.length < 20) functions.push({ name: match[1], parameters: String(match[2] || '').trim() });
    fnRegex.lastIndex = 0;
    return { path: filePath, language, imports: Array.from(new Set(imports)).slice(0, 20), types, functions, lineCount: content ? content.replace(/\r\n/g, '\n').split('\n').length : 0 };
  }
  function getRole(path) {
    const lower = String(path || '').toLowerCase();
    for (const role of ['controller', 'service', 'repository', 'dto', 'mapper', 'entity', 'config', 'security']) {
      if (lower.includes(role)) return role;
    }
    return 'other';
  }
  function sharedPrefixDepth(pathA, pathB) {
    const a = String(pathA || '').split('/');
    const b = String(pathB || '').split('/');
    let depth = 0;
    while (depth < a.length && depth < b.length && a[depth] === b[depth]) depth += 1;
    return depth;
  }
  function scoreSummary(summary, batchItems) {
    const summaryTokens = splitTokens(summary.path + ' ' + JSON.stringify(summary.types || []) + ' ' + JSON.stringify(summary.functions || []));
    const summaryRole = getRole(summary.path);
    let score = 0;
    for (const batchItem of batchItems) {
      const batchPath = String(batchItem.path || '').trim();
      const overlap = splitTokens(batchPath).filter((token) => summaryTokens.includes(token)).length;
      score += overlap * 2 + sharedPrefixDepth(summary.path, batchPath) * 3;
      if (getRole(batchPath) === summaryRole && summaryRole !== 'other') score += 4;
    }
    return score;
  }
  function selectRelevantMemory(currentFiles, batchItems) {
    const batchPaths = new Set(batchItems.map((item) => String(item.path || '').trim()));
    return currentFiles
      .filter((file) => isImplementationFile(file.path))
      .filter((file) => !batchPaths.has(String(file.path || '').trim()))
      .map(summarizeFile)
      .map((summary) => ({ summary, score: scoreSummary(summary, batchItems) }))
      .filter((entry) => entry.score > 0)
      .sort((a, b) => b.score - a.score || a.summary.path.localeCompare(b.summary.path))
      .slice(0, MAX_MEMORY_ITEMS)
      .map((entry) => entry.summary);
  }
  return $input.all().map((item) => {
    const json = item.json || {};
    const binary = item.binary || {};
    const reviewerFeedback = String(json.reviewerFeedback || json.feedback || '').trim() || 'Reviewer requested frontend changes without additional details.';
    const batchSize = Math.max(1, Number(json.batchSize || 4));
    const currentBatchFiles = Array.isArray(json.currentBatchFiles) && json.currentBatchFiles.length ? json.currentBatchFiles.slice(0, batchSize) : (Array.isArray(json.remainingFiles) ? json.remainingFiles.slice(0, batchSize) : []);
    if (!currentBatchFiles.length) throw new Error('No current refinement batch files available for frontend refinement.');
    const currentFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const currentFileMap = new Map(currentFiles.map((file) => [String(file.path || '').trim(), String(file.content ?? '')]));
    const batchPayload = currentBatchFiles.map((entry) => {
      const path = String(entry.path || '').trim();
      const action = String(entry.action || 'modify').trim().toLowerCase();
      const payload = { path, action };
      if (action === 'modify' && currentFileMap.has(path)) payload.currentContent = currentFileMap.get(path);
      return payload;
    });
    const attachmentBlocks = [];
    let totalChars = 0;
    for (const [key, entry] of Object.entries(binary).filter(([name]) => /^attachments?(?:_|$)/i.test(String(name)))) {
      if (totalChars >= ATTACHMENT_CHAR_LIMIT || !looksTextLike(entry, key)) continue;
      const text = decodeText(entry).trim();
      if (!text) continue;
      const take = Math.min(ATTACHMENT_FILE_CHAR_LIMIT, ATTACHMENT_CHAR_LIMIT - totalChars);
      attachmentBlocks.push(`Attachment: ${String(entry.fileName || key)}\n---\n${text.slice(0, take)}`);
      totalChars += Math.min(text.length, take);
    }
    const memory = selectRelevantMemory(currentFiles, currentBatchFiles);
    const currentPlanPaths = normalizeFiles(json.currentPlanFiles).map((file) => file.path);
    const userPrompt = [
      'FEEDBACK', reviewerFeedback,
      attachmentBlocks.length ? 'ATTACHMENTS\n' + attachmentBlocks.join('\n\n') : '',
      'CURRENT_PLAN', compactJson(currentPlanPaths),
      'BATCH', compactJson(batchPayload),
      memory.length ? 'MEMORY\n' + compactJson(memory) : '',
      'RULES', [
        'Generate only the files listed in BATCH with action create or modify.',
        'Do not output files whose action is remove.',
        'For modify actions, return the complete updated file content.',
        'For create actions, return the complete new file content.',
        'Keep changes tightly aligned with FEEDBACK and ATTACHMENTS.',
        'Preserve frontend consistency with the existing package.',
        'Return only valid JSON with a top-level files array.',
      ].join('\n'),
    ].filter(Boolean).join('\n');
    return { json: { ...json, currentBatchFiles, currentBatchFileCount: currentBatchFiles.length, allPlannedFiles: currentPlanPaths.map((path) => ({ path })), allowedOutputFiles: currentBatchFiles.map((entry) => ({ path: String(entry.path || '').trim() })), userPrompt, fullPromptLength: userPrompt.length, refinementMemoryLength: compactJson(memory).length }, binary };
  });
}

return feBuildRefinementChunkPrompt();

const item = $input.first() ?? { json: {}, binary: {} };

function getNodeItemsSafe(nodeName) {
  if (typeof $items !== 'function') return [];
  try {
    return $items(nodeName) || [];
  } catch (error) {
    const message = String(error?.message ?? error ?? '');
    if (message.includes("hasn't been executed") || message.includes('not executed')) {
      return [];
    }
    return [];
  }
}

function looksTextLike(binaryEntry, key) {
  const mime = String(binaryEntry?.mimeType ?? '').toLowerCase();
  const extRaw = String(binaryEntry?.fileExtension ?? '').toLowerCase();
