          output += '\f';
          index += 1;
          continue;
        }
        if (next === '"' || next === '\\' || next === '/') {
          output += next;
          index += 1;
          continue;
        }
        if (next === 'u' && /^[0-9a-fA-F]{4}$/.test(raw.slice(index + 2, index + 6))) {
          output += String.fromCharCode(parseInt(raw.slice(index + 2, index + 6), 16));
          index += 5;
          continue;
        }

        output += '\\' + next;
        index += 1;
      }

      return output;
    }

    function readStrictQuotedString(text, quoteStart) {
      for (let index = quoteStart + 1; index < text.length; index += 1) {
        if (text[index] === '"' && !isQuoteEscaped(text, index)) {
          return {
            value: decodeLooseJsonString(text.slice(quoteStart + 1, index)),
            endIndex: index,
          };
        }
      }
      throw new Error('Could not find closing quote for JSON string.');
    }

    function readStructuredJsonValue(text, valueStart) {
      const openingChar = text[valueStart];
      const closingChar = openingChar === '{' ? '}' : ']';
      const stack = [closingChar];
      let inString = false;
      let escaped = false;

      for (let index = valueStart + 1; index < text.length; index += 1) {
        const char = text[index];

        if (escaped) {
          escaped = false;
          continue;
        }

        if (char === '\\') {
          if (inString) escaped = true;
          continue;
        }

        if (char === '"') {
          inString = !inString;
          continue;
        }

        if (inString) continue;

        if (char === '{') {
          stack.push('}');
          continue;
        }
        if (char === '[') {
          stack.push(']');
          continue;
        }

        if (char === stack[stack.length - 1]) {
          stack.pop();
          if (!stack.length) {
            const rawValue = text.slice(valueStart, index + 1);
            return {
              value: JSON.parse(rawValue),
              endIndex: index,
            };
          }
        }
      }

      throw new Error('Could not find the end of generated file content JSON value.');
    }

    function readPrimitiveJsonValue(text, valueStart) {
      let endIndex = valueStart;
      while (endIndex < text.length && !/[\s,\}\]]/.test(text[endIndex])) {
        endIndex += 1;
      }

      const rawValue = text.slice(valueStart, endIndex).trim();
      if (!rawValue) {
        throw new Error('Generated file content JSON value is empty.');
      }

      return {
        value: JSON.parse(rawValue),
        endIndex: endIndex - 1,
      };
    }

    function readLooseJsonValue(text, valueStart) {
      if (valueStart < 0 || valueStart >= text.length) {
        throw new Error('Could not find content value in generated file object.');
      }

      const firstChar = text[valueStart];
      if (firstChar === '"') {
        return readStrictQuotedString(text, valueStart);
      }
      if (firstChar === '{' || firstChar === '[') {
        return readStructuredJsonValue(text, valueStart);
      }

      return readPrimitiveJsonValue(text, valueStart);
    }

    function canRecoverTruncatedTextFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      return lower.endsWith('.md') || lower.endsWith('.txt');
    }

    function decodeLooseJsonTail(raw) {
      let tail = String(raw || '');
      if (tail.endsWith('```')) {
        tail = tail.slice(0, -3);
      }
      return decodeLooseJsonString(tail).trimEnd();
    }

    function isLikelyIncompletePayloadError(error) {
      const message = String(error?.message ?? error ?? '');
      return (
        message.includes('Could not find closing quote') ||
        message.includes('Could not find the end of generated file content JSON value') ||
        message.includes('did not end after content field') ||
        message.includes('files array was not closed') ||
        message.includes('ended before files array closed') ||
        message.includes('Could not find content value')
      );
    }

    function parseLooseFilesPayload(text, allowPartial = false) {
      const filesKeyIndex = findPropertyKey(text, 'files', 0);
      if (filesKeyIndex === -1) {
        throw new Error('Chunk payload does not contain a files property.');
      }

      const arrayStart = text.indexOf('[', filesKeyIndex);
      if (arrayStart === -1) {
        throw new Error('Chunk payload files property does not contain an array.');
      }

      const files = [];
      let cursor = arrayStart + 1;

      while (cursor < text.length) {
        while (cursor < text.length && /[\s,]/.test(text[cursor])) cursor += 1;
        if (cursor >= text.length) {
          if (allowPartial) {
            return {
              files,
              recoveredPartialChunkPayload: true,
              ignoredIncompleteTrailingFile: true,
              recoveryReason: files.length
                ? 'Chunk payload ended before files array closed.'
                : 'Ignored incomplete trailing generated file because the model output ended before the payload closed.',
            };
          }
          break;
        }
        if (text[cursor] === ']') {
          return { files };
        }
        if (text[cursor] !== '{') {
          cursor += 1;
          continue;
        }

        let pathInfo = null;
        let contentValueStart = -1;

        try {
          const objectStart = cursor;
          const pathKeyIndex = findPropertyKey(text, 'path', objectStart);
          if (pathKeyIndex === -1) {
            throw new Error('Could not find path property in generated file object.');
          }
          const pathQuoteStart = findValueStart(text, pathKeyIndex);
          if (pathQuoteStart === -1 || text[pathQuoteStart] !== '"') {
            throw new Error('Could not find path string value in generated file object.');
          }
          pathInfo = readStrictQuotedString(text, pathQuoteStart);

          const contentKeyIndex = findPropertyKey(text, 'content', pathInfo.endIndex);
          if (contentKeyIndex === -1) {
            throw new Error('Could not find content property in generated file object.');
          }
          contentValueStart = findValueStart(text, contentKeyIndex);
          const contentInfo = readLooseJsonValue(text, contentValueStart);

          let objectEnd = contentInfo.endIndex + 1;
          while (objectEnd < text.length && /\s/.test(text[objectEnd])) objectEnd += 1;
          if (text[objectEnd] !== '}') {
            throw new Error('Generated file object did not end after content field.');
          }

          files.push({
            path: pathInfo.value,
            content: contentInfo.value,
          });

          cursor = objectEnd + 1;
        } catch (error) {
          if (allowPartial && pathInfo && contentValueStart !== -1 && text[contentValueStart] === '"' && canRecoverTruncatedTextFile(pathInfo.value)) {
            const recoveredContent = decodeLooseJsonTail(text.slice(contentValueStart + 1));
            if (recoveredContent.trim()) {
              files.push({
                path: pathInfo.value,
                content: recoveredContent,
              });
              return {
                files,
                recoveredPartialChunkPayload: true,
                recoveryReason: 'Recovered truncated text file content for ' + pathInfo.value,
              };
            }
          }
          if (allowPartial && (files.length || isLikelyIncompletePayloadError(error))) {
            return {
              files,
              recoveredPartialChunkPayload: true,
              ignoredIncompleteTrailingFile: true,
              recoveryReason: files.length
                ? String(error?.message ?? error ?? 'Partial chunk payload recovered.')
                : 'Ignored incomplete trailing generated file because the model output ended before the file was complete.',
            };
          }
          throw error;
        }
      }

      if (allowPartial) {
        return {
          files,
          recoveredPartialChunkPayload: true,
          ignoredIncompleteTrailingFile: true,
          recoveryReason: files.length
            ? 'Chunk payload files array was not closed.'
            : 'Ignored incomplete trailing generated file because the files array was not closed.',
        };
      }

      throw new Error('Chunk payload files array was not closed.');
    }

    function extractPayload(rawText) {
      const text = normalizeText(rawText);
      const candidates = [text];
      const balancedObject = extractBalancedObject(text);
      if (balancedObject) {
        candidates.push(balancedObject);
      }

      for (const candidate of candidates) {
        const parsed = parseCandidate(candidate);
        if (parsed) return parsed;
      }

      for (const candidate of candidates) {
        try {
          const parsed = parseLooseFilesPayload(candidate, false);
          if (parsed && Array.isArray(parsed.files)) {
            return parsed;
          }
        } catch {}
      }

      for (const candidate of candidates) {
        try {
          const parsed = parseLooseFilesPayload(candidate, true);
          if (parsed && Array.isArray(parsed.files)) {
            return parsed;
          }
        } catch {}
      }

      throw new Error('Could not extract a valid frontend chunk JSON payload from model output.');
    }

    function getNodeItemsSafe(nodeName) {
      if (typeof $items !== 'function') return [];
      try {
        return $items(nodeName) || [];
      } catch (error) {
        const message = String(error?.message ?? error ?? '');
        if (message.includes("hasn't been executed") || message.includes('not executed')) {
          return [];
        }
        throw error;
      }
    }

    function normalizeGeneratedContent(filePath, contentValue) {
      if (typeof contentValue === 'string') {
        return contentValue;
      }
      if (contentValue === null || contentValue === undefined) {
        return '';
      }
      if (typeof contentValue === 'object') {
        return JSON.stringify(contentValue, null, 2);
      }
      return String(contentValue);
    }

    const buildPromptItems = getNodeItemsSafe('FE - Build Refinement Chunk Prompt');

    return $input.all().map((item) => {
      const upstreamJson = buildPromptItems[0]?.json || {};
      const json = {
        ...upstreamJson,
        ...(item.json || {}),
      };
      const payload = extractPayload(json.text);
      const currentBatchFiles = Array.isArray(json.currentBatchFiles) && json.currentBatchFiles.length
        ? json.currentBatchFiles
        : (Array.isArray(json.remainingFiles) ? json.remainingFiles.slice(0, Number(json.batchSize || 15)) : []);
      const currentBatchPaths = new Set(currentBatchFiles.map((file) => String(file.path || '').trim()).filter(Boolean));
      const plannedFiles = Array.isArray(json.allPlannedFiles) && json.allPlannedFiles.length
        ? json.allPlannedFiles
        : [];
      const allowedOutputFiles = Array.isArray(json.allowedOutputFiles) && json.allowedOutputFiles.length
        ? json.allowedOutputFiles
        : currentBatchFiles;
      const allowedPaths = new Set(allowedOutputFiles.map((file) => String(file.path || '').trim()).filter(Boolean));
      const generatedOutsideCurrentBatch = [];
      const ignoredUnplannedGeneratedFiles = [];
      const ignoredDuplicateGeneratedFiles = [];

      if (!Array.isArray(payload.files)) {
        throw new Error('Chunk payload must include a files array.');
      }

      const seen = new Set();
      const normalizedFiles = [];
      for (let index = 0; index < payload.files.length; index += 1) {
        const file = payload.files[index];
        if (!file || typeof file !== 'object' || Array.isArray(file)) {
          throw new Error('Generated file entry at index ' + index + ' must be an object.');
        }

        const filePath = String(file.path || '').trim();
        const content = normalizeGeneratedContent(filePath, file.content);
        if (!filePath.startsWith('frontend/')) {
          throw new Error('Generated invalid file path: ' + (filePath || '<empty>'));
        }
        if (!allowedPaths.has(filePath)) {
          ignoredUnplannedGeneratedFiles.push(filePath);
          continue;
        }
        if (!currentBatchPaths.has(filePath)) {
          generatedOutsideCurrentBatch.push(filePath);
        }
        if (seen.has(filePath)) {
          ignoredDuplicateGeneratedFiles.push(filePath);
          continue;
        }

        seen.add(filePath);
        normalizedFiles.push({
          path: filePath,
          content,
        });
      }

      return {
        json: {
          ...json,
          recoveredPartialChunkPayload: payload.recoveredPartialChunkPayload === true,
          partialChunkRecoveryReason: payload.recoveryReason || '',
          ignoredIncompleteTrailingFile: payload.ignoredIncompleteTrailingFile === true,
          generatedFilesThisIteration: normalizedFiles,
          generatedFileCountThisIteration: normalizedFiles.length,
          generatedFilesOutsideCurrentBatch: generatedOutsideCurrentBatch,
          generatedFilesOutsideCurrentBatchCount: generatedOutsideCurrentBatch.length,
          ignoredUnplannedGeneratedFiles,
          ignoredUnplannedGeneratedFileCount: ignoredUnplannedGeneratedFiles.length,
          ignoredDuplicateGeneratedFiles,
          ignoredDuplicateGeneratedFileCount: ignoredDuplicateGeneratedFiles.length,
        },
        binary: item.binary ?? {},
      };
    });
  }
return feCleanChunkResponse();

function decodeEscapedText(text) {
  let value = String(text ?? '');
  for (let i = 0; i < 2; i += 1) {
    const trimmed = value.trim();
    if (!trimmed) return trimmed;
    if ((trimmed.startsWith('"') && trimmed.endsWith('"')) || (trimmed.startsWith("'") && trimmed.endsWith("'"))) {
      try {
        const parsed = JSON.parse(trimmed.startsWith("'") ? `"${trimmed.slice(1, -1).replace(/\\/g, '\\\\').replace(/"/g, '\\"')}"` : trimmed);
        if (typeof parsed === 'string') {
          value = parsed;
          continue;
        }
      } catch {}
    }
    if (trimmed.includes('\\n') || trimmed.includes('\\"') || trimmed.includes('\\t') || trimmed.includes('\\r')) {
      value = trimmed
        .replace(/\\r\\n/g, '\n')
        .replace(/\\n/g, '\n')
        .replace(/\\r/g, '\r')
        .replace(/\\t/g, '\t')
        .replace(/\\"/g, '"')
        .replace(/\\\\/g, '\\');
      continue;
    }
    break;
  }
  return value;
}

function normalizeText(raw) {
  let text = String(raw ?? '').trim();
  if (!text) {
    throw new Error('Frontend refinement plan model output is empty.');
  }
  text = decodeEscapedText(text).trim();
  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced) {
    text = decodeEscapedText(fenced[1]).trim();
  }
  return text;
}

function parseJsonCandidates(text) {
  const normalized = normalizeText(text);
  const candidates = [normalized];
  const objectStart = normalized.indexOf('{');
  const objectEnd = normalized.lastIndexOf('}');
  if (objectStart >= 0 && objectEnd > objectStart) {
    candidates.push(normalized.slice(objectStart, objectEnd + 1));
  }
  const arrayStart = normalized.indexOf('[');
  const arrayEnd = normalized.lastIndexOf(']');
  if (arrayStart >= 0 && arrayEnd > arrayStart) {
    candidates.push(normalized.slice(arrayStart, arrayEnd + 1));
  }
  for (const candidate of candidates) {
    try {
      return JSON.parse(candidate);
    } catch {}
  }
  return null;
}

function normalizeAction(value) {
  const action = String(value ?? '').trim().toLowerCase();
  if (!action) return '';
  if (['modify', 'modified', 'update', 'updated', 'change', 'changed', 'edit', 'edited', 'patch', 'replace'].includes(action)) {
    return 'modify';
  }
  if (['create', 'created', 'add', 'added', 'new', 'insert'].includes(action)) {
    return 'create';
  }
  if (['remove', 'removed', 'delete', 'deleted', 'drop'].includes(action)) {
    return 'remove';
  }
  return '';
}

function extractEntriesFromObjectMap(payload) {
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) return [];
  const entries = [];
  for (const [key, value] of Object.entries(payload)) {
    const path = String(key ?? '').trim();
    if (!path.startsWith('frontend/')) continue;
    if (typeof value === 'string') {
      const action = normalizeAction(value);
      if (action) entries.push({ path, action });
      continue;
    }
    if (value && typeof value === 'object') {
      const action = normalizeAction(value.action ?? value.type ?? value.operation ?? value.op);
      if (action) entries.push({ path, action });
    }
  }
  return entries;
}

function extractRegexEntries(text) {
  const normalized = normalizeText(text);
  const results = [];
  const pattern = /"path"\s*:\s*"([^"]+)"[\s,;\r\n]*"action"\s*:\s*"([^"]+)"/gi;
  for (const match of normalized.matchAll(pattern)) {
    results.push({ path: match[1], action: match[2] });
  }
  return results;
}

function collectRawFiles(payload, originalText) {
  if (Array.isArray(payload)) return payload;
  if (Array.isArray(payload?.files)) return payload.files;
  if (Array.isArray(payload?.changes)) return payload.changes;
  if (Array.isArray(payload?.items)) return payload.items;
  if (Array.isArray(payload?.actions)) return payload.actions;
  const objectMapEntries = extractEntriesFromObjectMap(payload);
  if (objectMapEntries.length) return objectMapEntries;
  const regexEntries = extractRegexEntries(originalText);
  if (regexEntries.length) return regexEntries;
  return [];
}

function normalizePlan(payload, originalText) {
  const rawFiles = collectRawFiles(payload, originalText);
  const seen = new Set();
  const files = [];
  for (const entry of rawFiles) {
    if (!entry || typeof entry !== 'object') continue;
    const path = String(entry.path ?? entry.file ?? entry.filePath ?? '').trim();
    const action = normalizeAction(entry.action ?? entry.type ?? entry.operation ?? entry.op);
    if (!path || !path.startsWith('frontend/')) continue;
    if (!action) continue;
    if (seen.has(path)) continue;
    seen.add(path);
    files.push({ path, action });
  }
  if (!files.length) {
    throw new Error('Frontend refinement plan did not contain any valid file actions.');
  }
  return { files };
}

const item = $input.first();
const json = item?.json ?? {};
const rawText = json.text;
const payload = parseJsonCandidates(rawText) ?? rawText;
const plan = normalizePlan(payload, rawText);

return [{
  json: {
    ...json,
    ...plan,
    refinementPlanFiles: plan.files,
    fileCount: plan.files.length,
    revisionNumber: Number(json.revisionNumber ?? 0) || 0,
    plannedFiles: json.plannedFiles ?? [],
    firstIterationFiles: json.firstIterationFiles ?? [],
    currentFiles: json.currentFiles ?? [],
    previousPlanFiles: json.previousPlanFiles ?? [],
    frontendStructure: json.frontendStructure ?? json.structurePlan ?? '',
    frontendStructureObject: json.frontendStructureObject ?? json.structurePlanObject ?? null,
    structurePlan: json.structurePlan ?? json.frontendStructure ?? '',
    structurePlanObject: json.structurePlanObject ?? json.frontendStructureObject ?? null,
  },
  ...(item?.binary && Object.keys(item.binary).length > 0 ? { binary: item.binary } : {}),
}];

function beCleanStructure() {
  function parseJsonCandidate(raw) {
    try {
      const parsed = JSON.parse(raw);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        return parsed;
      }
    } catch {}
    return null;
  }

  function normalizeText(raw) {
    let text = String(raw ?? '').trim();
    if (!text) {
      throw new Error('Frontend structure model output is empty.');
    }

    if (text.startsWith('```')) {
      const firstNewlineIndex = text.indexOf('\n');
      if (firstNewlineIndex !== -1) {
        const openingFence = text.slice(0, firstNewlineIndex).trim();
        if (/^```(?:json)?$/i.test(openingFence)) {
          text = text.slice(firstNewlineIndex + 1);

          const trailingFenceIndex = text.lastIndexOf('\n```');
          if (trailingFenceIndex !== -1 && text.slice(trailingFenceIndex).trim() === '```') {
            text = text.slice(0, trailingFenceIndex).trim();
          } else if (text.endsWith('```')) {
            text = text.slice(0, -3).trim();
          } else {
            text = text.trim();
          }
        }
      }
    }

    return text;
  }

  function extractBalancedObject(text) {
    let depth = 0;
    let start = -1;
    let inString = false;
    let escaped = false;

    for (let index = 0; index < text.length; index += 1) {
      const char = text[index];

      if (escaped) {
        escaped = false;
        continue;
      }

      if (char === '\\') {
        if (inString) escaped = true;
        continue;
      }

      if (char === '"') {
        inString = !inString;
        continue;
      }

      if (inString) continue;

      if (char === '{') {
        if (depth === 0) start = index;
        depth += 1;
        continue;
      }

      if (char === '}') {
        if (depth > 0) {
          depth -= 1;
          if (depth === 0 && start !== -1) {
            return text.slice(start, index + 1);
          }
        }
      }
    }

    return null;
  }

  function extractStructure(rawText) {
    const text = normalizeText(rawText);
    const candidates = [text];
    const balancedObject = extractBalancedObject(text);
    if (balancedObject) {
      candidates.push(balancedObject);
    }

    for (const candidate of candidates) {
      const parsed = parseJsonCandidate(candidate);
      if (parsed) return parsed;
    }

    throw new Error('Could not extract a valid frontend structure JSON document from model output.');
  }

  function normalizeFileEntry(file, index) {
    if (typeof file === 'string') {
      const path = file.trim();
      if (!path) {
        throw new Error(`files[${index}] must not be empty.`);
      }
      return { path };
    }

    if (!file || typeof file !== 'object' || Array.isArray(file)) {
      throw new Error(`files[${index}] must be a string path or an object with path.`);
    }

    const filePath = String(file.path || '').trim();
    if (!filePath) {
      throw new Error(`files[${index}].path is required.`);
    }

    return { path: filePath };
  }

  function validateAndNormalizeStructure(payload) {
    if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
      throw new Error('Frontend structure must be an object.');
    }
    if (!Array.isArray(payload.files)) {
      throw new Error('Frontend structure must contain a files array.');
    }
    if (!payload.files.length) {
      throw new Error('Frontend structure files array must not be empty.');
    }

    const seen = new Set();
    const normalizedFiles = payload.files.map((file, index) => {
      const normalized = normalizeFileEntry(file, index);
      const filePath = normalized.path;
      if (!filePath.startsWith('frontend/')) {
        throw new Error(`files[${index}].path must start with "frontend/".`);
      }
      if (seen.has(filePath)) {
        throw new Error(`Duplicate frontend structure file path: ${filePath}`);
      }
      seen.add(filePath);
      return normalized;
    });

    return { files: normalizedFiles };
  }

  const item = $input.first();
  const structure = validateAndNormalizeStructure(extractStructure(item?.json?.text));

  return [{
    json: {
      ...(item?.json ?? {}),
      frontendStructure: JSON.stringify(structure, null, 2),
      frontendStructureObject: structure,
      structureFileCount: structure.files.length,
    },
    binary: item?.binary ?? {},
  }];
}
return beCleanStructure();

async function feCompactContextArtifacts() {
  const items = $input.all();
  if (!items.length) {
    throw new Error('Frontend context compactor received no input.');
  }

  async function readBinaryText(itemIndex, propertyName, fallbackFileName) {
    const item = items[itemIndex];
    const binary = item.binary?.[propertyName];
    if (!binary) return null;
    const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, propertyName);
    return {
      fileName: binary.fileName || fallbackFileName,
      text: buffer.toString('utf8'),
    };
  }

  function cleanText(value) {
    return String(value || '').replace(/\s+/g, ' ').trim();
  }

  function slugify(value, fallback) {
    const text = cleanText(value).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
    return text || fallback;
  }

  function normalizeText(text) {
    return String(text || '').replace(/\u0000/g, '').replace(/\r\n/g, '\n').replace(/\r/g, '\n').trim();
  }

  function isText(element) {
    return element && element.type === 'text' && cleanText(element.text);
  }

  function isRectangleLike(element) {
    return element && (element.type === 'rectangle' || element.type === 'frame');
  }

  function within(element, box, margin = 0) {
    const x = Number(element.x || 0);
    const y = Number(element.y || 0);
    return x >= box.x - margin && y >= box.y - margin && x <= box.x + box.width + margin && y <= box.y + box.height + margin;
  }

  function boxOf(element) {
    return {
      x: Number(element.x || 0),
      y: Number(element.y || 0),
      width: Number(element.width || 0),
      height: Number(element.height || 0),
    };
  }

  function area(box) {
    return Math.max(0, box.width) * Math.max(0, box.height);
  }

  function topColors(elements, key, limit) {
    const counts = new Map();
    for (const element of elements) {
      const value = String(element?.[key] || '').trim();
      if (!value || value === 'transparent') continue;
      counts.set(value, (counts.get(value) || 0) + 1);
    }
    return [...counts.entries()].sort((a, b) => b[1] - a[1]).slice(0, limit).map(([value]) => value);
  }

  function textElements(elements) {
    return elements.filter(isText).map((element) => ({
      text: cleanText(element.text),
      x: Number(element.x || 0),
      y: Number(element.y || 0),
      fontSize: Number(element.fontSize || 0),
      width: Number(element.width || 0),
      height: Number(element.height || 0),
    }));
  }

  function pickTitle(texts, box, fallback) {
    const candidates = texts
      .filter((text) => text.y <= box.y + Math.max(120, box.height * 0.18))
      .sort((a, b) => (b.fontSize - a.fontSize) || (a.y - b.y) || (a.x - b.x));
    return candidates.length ? candidates[0].text : fallback;
  }

  function uniqueLabels(values, limit) {
    const seen = new Set();
    const result = [];
    for (const value of values) {
      const normalized = cleanText(value);
      if (!normalized || seen.has(normalized)) continue;
      seen.add(normalized);
      result.push(normalized);
      if (result.length >= limit) break;
    }
    return result;
  }

  function uniqueObjects(values, limit, keyFn) {
    const seen = new Set();
    const result = [];
    for (const value of values) {
      const key = keyFn(value);
      if (!key || seen.has(key)) continue;
      seen.add(key);
      result.push(value);
      if (result.length >= limit) break;
    }
    return result;
  }

  function textsInside(texts, box) {
    return texts.filter((text) => within(text, box, 4)).sort((a, b) => (a.y - b.y) || (a.x - b.x));
  }

  function rectsInside(elements, box, predicate) {
    return elements
      .filter((element) => isRectangleLike(element) && within(element, box, 4) && predicate(element))
      .sort((a, b) => (Number(a.y || 0) - Number(b.y || 0)) || (Number(a.x || 0) - Number(b.x || 0)));
  }

  function nearestLabel(rect, texts) {
    const rectBox = boxOf(rect);
    const candidates = texts
      .filter((text) => text.x >= rectBox.x - 40 && text.x <= rectBox.x + rectBox.width + 20 && text.y >= rectBox.y - 48 && text.y <= rectBox.y + 14)
      .sort((a, b) => (Math.abs(rectBox.y - a.y) - Math.abs(rectBox.y - b.y)) || (a.x - b.x));
    return candidates.length ? candidates[0].text : null;
  }

  function fieldSummary(elements, texts, box) {
    const result = [];
    for (const rect of rectsInside(elements, box, (rect) => {
      const width = Number(rect.width || 0);
      const height = Number(rect.height || 0);
      return width >= 120 && width <= 640 && height >= 28 && height <= 96;
    })) {
      const label = nearestLabel(rect, texts);
      if (!label) continue;
      result.push({ label: cleanText(label), kind: 'field' });
      if (result.length >= 24) break;
    }
    return uniqueObjects(result, 24, (entry) => entry.label);
  }

  function tableSummary(elements, texts, box) {
    const result = [];
    for (const rect of rectsInside(elements, box, (rect) => Number(rect.width || 0) >= 420 && Number(rect.height || 0) >= 160)) {
      const rectBox = boxOf(rect);
      const innerTexts = textsInside(texts, rectBox);
      if (innerTexts.length < 8) continue;
      const headerTexts = innerTexts.filter((text) => text.y <= rectBox.y + 72).map((text) => text.text);
      result.push({ kind: 'table', columns: uniqueLabels(headerTexts, 10) });
      if (result.length >= 6) break;
    }
    return result;
  }

  function summarizeContainer(container, allElements, allTexts, index, kind) {
    const box = boxOf(container);
    const texts = textsInside(allTexts, box);
    const fallbackTitle = `${kind === 'dialog' ? 'Dialog' : 'Screen'} ${index + 1}`;
    const title = pickTitle(texts, box, fallbackTitle);
    const navTexts = texts.filter((text) => text.y <= box.y + 110 && text.text !== title).map((text) => text.text);
    const keyTexts = texts.filter((text) => text.text !== title).slice(0, 30).map((text) => text.text);
    return {
      id: slugify(title, `${kind}-${index + 1}`),
      title,
      kind,
      size: { width: box.width, height: box.height },
      nav: uniqueLabels(navTexts, 12),
      fields: fieldSummary(allElements, allTexts, box),
      tables: tableSummary(allElements, allTexts, box),
      keyTexts: uniqueLabels(keyTexts, 30),
    };
  }

  function summarizeDesign(designObject) {
    const elements = Array.isArray(designObject?.elements) ? designObject.elements : [];
    const texts = textElements(elements);
    const rectangles = elements.filter(isRectangleLike);

    const screenCandidates = rectangles
      .filter((rect) => Number(rect.width || 0) >= 900 && Number(rect.height || 0) >= 600)
      .sort((a, b) => area(boxOf(b)) - area(boxOf(a)));

    const screens = [];
    for (const candidate of screenCandidates) {
      const box = boxOf(candidate);
      const isNested = screens.some((existing) => {
        const existingBox = boxOf(existing);
        return box.x >= existingBox.x && box.y >= existingBox.y && box.x + box.width <= existingBox.x + existingBox.width && box.y + box.height <= existingBox.y + existingBox.height;
      });
      if (!isNested) screens.push(candidate);
      if (screens.length >= 12) break;
    }

    const screenBoxes = screens.map(boxOf);
    const dialogCandidates = rectangles.filter((rect) => {
      const width = Number(rect.width || 0);
      const height = Number(rect.height || 0);
      if (width < 280 || width > 1000 || height < 160 || height > 800) return false;
      const box = boxOf(rect);
      return !screenBoxes.some((screenBox) => box.x === screenBox.x && box.y === screenBox.y && box.width === screenBox.width && box.height === screenBox.height);
    }).slice(0, 20);

    const summarizedScreens = screens.length
      ? screens.map((screen, index) => summarizeContainer(screen, elements, texts, index, 'screen'))
      : [{
          id: 'screen-1',
          title: 'Primary Screen',
          kind: 'screen',
          size: { width: 0, height: 0 },
          nav: [],
          fields: [],
          tables: [],
          keyTexts: uniqueLabels(texts.slice(0, 60).map((text) => text.text), 60),
        }];

    const summarizedDialogs = dialogCandidates.map((dialog, index) => summarizeContainer(dialog, elements, texts, index, 'dialog'));

    return {
      meta: {
        sourceFormat: 'Excalidraw',
        originalElementCount: elements.length,
        screenCount: summarizedScreens.length,
        dialogCount: summarizedDialogs.length,
      },
      theme: {
        topStrokeColors: topColors(elements, 'strokeColor', 8),
        topFillColors: topColors(elements, 'backgroundColor', 8),
      },
      screens: summarizedScreens,
      dialogs: summarizedDialogs,
      looseTexts: uniqueLabels(texts.filter((text) => text.text.length >= 3).map((text) => text.text), 80),
    };
  }

  function binaryFromText(propertyName, fileName, text, mimeType) {
    return [
      propertyName,
      {
        data: Buffer.from(String(text || ''), 'utf8').toString('base64'),
        fileName,
        mimeType,
      },
    ];
  }
  function compactRequirementsText(text) {
    return String(text || '')
      .replace(/\\u0000/g, '')
      .replace(/\\r\\n/g, '\\n')
      .replace(/\\r/g, '\\n')
      .replace(/[ \\t]+/g, ' ')
      .trim();
  }

  function compactOpenapiText(text) {
    const normalized = normalizeText(text);
    if (!normalized) return '';
    if (normalized.startsWith('{')) {
      try {
        return JSON.stringify(JSON.parse(normalized));
      } catch {}
    }
    return normalized.replace(/[ \\t]+$/gm, '').replace(/\\n{3,}/g, '\\n\\n');
  }
  let requirements = null;
  let openapi = null;
  let design = null;
  for (let itemIndex = 0; itemIndex < items.length; itemIndex += 1) {
    if (!requirements) requirements = await readBinaryText.call(this, itemIndex, 'requirements', 'requirements-compact.txt');
    if (!openapi) openapi = await readBinaryText.call(this, itemIndex, 'openapiSpec', 'openapi-compact.json');
    if (!design) design = await readBinaryText.call(this, itemIndex, 'design', 'design.excalidraw.json');
  }

  if (!requirements) throw new Error('Missing compact requirements binary for frontend context.');
  if (!openapi) throw new Error('Missing compact openapiSpec binary for frontend context.');
  if (!design) throw new Error('Missing design binary for frontend context.');
  const compactedRequirementsText = compactRequirementsText(requirements.text);
  if (!compactedRequirementsText) throw new Error('Requirements text is empty after frontend compaction.');
  const compactedOpenapiText = compactOpenapiText(openapi.text);
  if (!compactedOpenapiText) throw new Error('OpenAPI text is empty after frontend compaction.');

  const designRaw = normalizeText(design.text);
  if (!designRaw) {
    throw new Error('Design text is empty, cannot compact frontend design context.');
  }

  let designObject;
  try {
    designObject = JSON.parse(designRaw);
  } catch (error) {
    throw new Error('Failed to parse design JSON for frontend context compaction: ' + String(error?.message || error));
  }

  const compactedDesign = summarizeDesign(designObject);
  const compactedDesignText = JSON.stringify(compactedDesign);

  return [{
    json: {
      designCompactionStats: {
        sourceBytes: Buffer.byteLength(designRaw, 'utf8'),
        compactBytes: Buffer.byteLength(compactedDesignText, 'utf8'),
        screenCount: compactedDesign.meta.screenCount,
        dialogCount: compactedDesign.meta.dialogCount,
      },
    },
    binary: Object.fromEntries([
      binaryFromText('requirements', 'requirements-compact.txt', compactedRequirementsText, 'text/plain'),
      binaryFromText('openapiSpec', 'openapi-compact.json', compactedOpenapiText, 'application/json'),
      binaryFromText('designSpec', 'design-compact.json', compactedDesignText, 'application/json'),
    ]),
  }];
}

return await feCompactContextArtifacts.call(this);

function beInitGenerationState() {
  const item = $input.first();
  if (!item) {
    throw new Error('No frontend structure item received.');
  }

  const json = item.json || {};
  const structure = json.frontendStructureObject || JSON.parse(String(json.frontendStructure || '{}'));
  if (!Array.isArray(structure.files) || !structure.files.length) {
    throw new Error('Frontend structure does not contain any files.');
  }

  const seen = new Set();
  const files = structure.files.map((file, index) => {
    const filePath = typeof file === 'string'
      ? String(file).trim()
      : String(file?.path || '').trim();
    if (!filePath.startsWith('frontend/')) {
      throw new Error(`Invalid frontend structure path at index ${index}: ${filePath || '<empty>'}`);
    }
    if (seen.has(filePath)) {
      throw new Error(`Duplicate frontend structure path: ${filePath}`);
    }
    seen.add(filePath);
    return { path: filePath };
  });

  return [{
    json: {
      ...json,
      allPlannedFiles: files,
      remainingFiles: files,
      generatedFiles: [],
      generatedFilePaths: [],
      lastIterationFiles: [],
      totalPlannedFiles: files.length,
      generatedFileCountTotal: 0,
      remainingFileCount: files.length,
      batchSize: 15,
      currentBatchFiles: files.slice(0, 15),
      currentBatchFileCount: Math.min(files.length, 15),
      iteration: 1,
      hasRemainingFiles: 'yes',
    },
    binary: item.binary ?? {},
  }];
}

return beInitGenerationState();

async function feInitRefinementState() {
  const item = $input.first();
  if (!item) throw new Error('No frontend refinement context item received.');

  function normalizeFiles(value) {
    const files = Array.isArray(value) ? value : [];
    return files.map((entry) => {
      if (typeof entry === 'string') return { path: entry.trim() };
      if (entry && typeof entry === 'object') return { path: String(entry.path ?? '').trim() };
      return { path: '' };
    }).filter((entry) => entry.path);
  }

  function decodeBinaryText(binaryEntry) {
    try {
      const raw = String(binaryEntry?.data ?? '');
      return raw && raw !== 'filesystem-v2' ? Buffer.from(raw, 'base64').toString('utf8') : '';
    } catch {
      return '';
    }
  }

  async function readBinaryText(binary, propertyName, binaryEntry) {
    try {
      if (typeof this?.helpers?.getBinaryDataBuffer === 'function') {
        const index = Array.isArray($input?.all?.()) ? 0 : 0;
        const buffer = await this.helpers.getBinaryDataBuffer(index, propertyName);
        if (buffer) return buffer.toString('utf8');
      }
    } catch {}
    return decodeBinaryText(binaryEntry);
  }

  function uniquePaths(paths) {
    const seen = new Set();
    const output = [];
    for (const value of paths || []) {
      const path = String(value?.path ?? value ?? '').trim();
      if (!path || seen.has(path)) continue;
      seen.add(path);
      output.push({ path });
    }
    return output;
  }

  function parseStructure(text) {
    const raw = String(text ?? '').trim();
    if (!raw) return null;
    try {
      const parsed = JSON.parse(raw);
      const files = normalizeFiles(parsed?.files);
      return files.length ? { files } : null;
    } catch {
      return null;
    }
  }

  function normalizeFrontendPath(rawPath, frontendRoot, rawDirectory) {
    const normalizedRoot = String(frontendRoot || 'frontend').replace(/\\/g, '/').trim().replace(/\/+$/, '') || 'frontend';
    const directory = String(rawDirectory ?? '').replace(/\\/g, '/').trim().replace(/^\.\//, '').replace(/\/+$/, '');
    const fileName = String(rawPath ?? '').replace(/\\/g, '/').trim().replace(/^\.\//, '');
    const combined = [directory, fileName]
      .filter(Boolean)
      .join('/')
      .replace(/\/+/g, '/')
      .replace(/^\.\//, '')
      .replace(/\/+/g, '/');
    if (!combined) return '';
    if (combined === normalizedRoot || combined === normalizedRoot + '.zip') return '';
    if (combined.startsWith(normalizedRoot + '/')) return combined;
    return normalizedRoot + '/' + combined.replace(/^\/+/, '');
  }

  async function collectCurrentFrontendFiles(binary, frontendRoot) {
    const byPath = new Map();
    for (const [propertyName, entry] of Object.entries(binary || {})) {
      if (propertyName === 'frontendZip' || propertyName === 'frontendStructure') continue;
      const fileName = String(entry?.fileName ?? '').trim();
      const normalizedPath = normalizeFrontendPath(fileName, frontendRoot, entry?.directory);
      const isDecompressedEntry = /^current_/i.test(propertyName) || String(entry?.directory ?? '').replace(/\\/g, '/').trim() === frontendRoot;
      if ((!isDecompressedEntry && !normalizedPath.startsWith(frontendRoot + '/')) || !normalizedPath || normalizedPath.endsWith('.zip')) continue;
      byPath.set(normalizedPath, { path: normalizedPath, content: await readBinaryText(binary, propertyName, entry) });
    }
    return Array.from(byPath.values()).sort((a, b) => a.path.localeCompare(b.path));
  }

  const json = item.json || {};
  const binary = item.binary || {};
  const rawPlanEntries = Array.isArray(json.refinementPlanFiles) ? json.refinementPlanFiles : (Array.isArray(json.files) ? json.files : []);
  const allowedActions = new Set(['modify', 'create', 'remove']);
  const seenPlanPaths = new Set();
  const refinementPlanFiles = [];
  for (const entry of rawPlanEntries) {
    if (!entry || typeof entry !== 'object') continue;
    const path = String(entry.path ?? '').trim();
    const action = String(entry.action ?? '').trim().toLowerCase();
    if (!path.startsWith('frontend/') || !allowedActions.has(action) || seenPlanPaths.has(path)) continue;
    seenPlanPaths.add(path);
    refinementPlanFiles.push({ path, action });
  }
  if (!refinementPlanFiles.length) {
    throw new Error('Frontend refinement plan did not contain any valid file actions.');
  }

  const frontendRoot = String(json.frontendRoot ?? 'frontend').trim() || 'frontend';
  const frontendFiles = await collectCurrentFrontendFiles.call(this, binary, frontendRoot);
  if (!frontendFiles.length) {
    throw new Error('Current frontend ZIP could not be unpacked into files for refinement.');
  }
  const frontendFileMap = new Map(frontendFiles.map((file) => [file.path, file]));
  const structureTextCandidates = [
    String(json.frontendStructure ?? '').trim(),
    String(json.structurePlan ?? '').trim(),
    decodeBinaryText(binary.frontendStructure),
  ].filter(Boolean);
  const parsedStructure = structureTextCandidates.map(parseStructure).find(Boolean);
  const currentPlanFiles = uniquePaths(parsedStructure?.files?.length ? parsedStructure.files : frontendFiles.map((file) => ({ path: file.path })));

  const removePaths = new Set(refinementPlanFiles.filter((file) => file.action === 'remove').map((file) => file.path));
  const workItems = refinementPlanFiles
    .filter((file) => file.action !== 'remove')
    .map((file) => ({ path: file.path, action: file.action, currentExists: frontendFileMap.has(file.path) }));

  const currentFrontendFiles = frontendFiles.filter((file) => !removePaths.has(file.path));
  const currentPlanPaths = currentPlanFiles.filter((file) => !removePaths.has(file.path));
  for (const workItem of workItems) {
    if (!currentPlanPaths.some((file) => file.path === workItem.path)) currentPlanPaths.push({ path: workItem.path });
  }

  const batchSize = Math.max(1, Number(json.refinementBatchSize ?? 4));
  const currentBatchFiles = workItems.slice(0, batchSize);
  const frontendStructureObject = { files: currentPlanPaths };
  const frontendStructure = JSON.stringify(frontendStructureObject);

  return [{
    json: {
      ...json,
      refinementPlanFiles,
      removeFilePaths: Array.from(removePaths),
      generatedFiles: currentFrontendFiles,
      generatedFilePaths: currentFrontendFiles.map((file) => file.path),
      generatedFileCountTotal: currentFrontendFiles.length,
      currentPlanFiles: currentPlanPaths,
      plannedFiles: currentPlanPaths,
      frontendStructure,
      frontendStructureObject,
      remainingFiles: workItems,
      remainingFileCount: workItems.length,
      currentBatchFiles,
      currentBatchFileCount: currentBatchFiles.length,
      allPlannedFiles: currentPlanPaths,
      allowedOutputFiles: currentBatchFiles.map((file) => ({ path: file.path })),
      lastIterationFiles: [],
      recentImplementationSummaries: [],
      generatedImplementationIndex: [],
      batchSize,
      iteration: 1,
      hasRemainingFiles: workItems.length > 0 ? 'yes' : 'no',
    },
    binary,
  }];
}

return feInitRefinementState();

const item = $input.first();
const json = item?.json ?? {};
const revisionNumber = Math.max(0, Math.trunc(Number(json.revisionNumber ?? 0) || 0));
const fileCount = Math.max(0, Math.trunc(Number(json.fileCount ?? 0) || 0));
const zipDownloadUrl = String(json.zipDownloadUrl ?? '').trim();
if (!zipDownloadUrl) throw new Error('Review ZIP download URL is missing.');
const zipDownloadToken = String(json.zipDownloadToken ?? '').trim();
