return [output];

function beUpdateGenerationState() {
    function detectLanguage(filePath) {
      const lower = String(filePath || '').toLowerCase();
      if (lower.endsWith('.java')) return 'java';
      if (lower.endsWith('.kt')) return 'kotlin';
      if (lower.endsWith('.py')) return 'python';
      if (lower.endsWith('.ts')) return 'typescript';
      if (lower.endsWith('.tsx')) return 'tsx';
      if (lower.endsWith('.js')) return 'javascript';
      if (lower.endsWith('.jsx')) return 'jsx';
      if (lower.endsWith('.cs')) return 'csharp';
      if (lower.endsWith('.go')) return 'go';
      if (lower.endsWith('.rb')) return 'ruby';
      if (lower.endsWith('.php')) return 'php';
      if (lower.endsWith('.rs')) return 'rust';
      if (lower.endsWith('.swift')) return 'swift';
      if (lower.endsWith('.scala')) return 'scala';
      if (lower.endsWith('.c')) return 'c';
      if (lower.endsWith('.cpp') || lower.endsWith('.cc') || lower.endsWith('.cxx')) return 'cpp';
      if (lower.endsWith('.h') || lower.endsWith('.hpp')) return 'cpp-header';
      return 'other';
    }

    function isImplementationFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      if (!lower.startsWith('frontend/')) return false;
      if (lower.includes('/src/test/') || lower.includes('/tests/') || lower.includes('/test/')) return false;
      if (lower.includes('/resources/') || lower.includes('/db/') || lower.includes('/docs/') || lower.includes('/helm/')) return false;
      if (lower.endsWith('.md') || lower.endsWith('.txt') || lower.endsWith('.yaml') || lower.endsWith('.yml') || lower.endsWith('.xml') || lower.endsWith('.properties') || lower.endsWith('.sql') || lower.endsWith('.json') || lower.endsWith('.csv')) return false;
      return new Set(['java', 'kotlin', 'python', 'typescript', 'tsx', 'javascript', 'jsx', 'csharp', 'go', 'ruby', 'php', 'rust', 'swift', 'scala', 'c', 'cpp', 'cpp-header']).has(detectLanguage(filePath));
    }

    function uniqueStrings(values, limit) {
      const seen = new Set();
      const output = [];
      for (const value of values || []) {
        const normalized = String(value || '').trim();
        if (!normalized || seen.has(normalized)) continue;
        seen.add(normalized);
        output.push(normalized);
        if (output.length >= limit) break;
      }
      return output;
    }

    function matchAll(text, regex, mapper, limit) {
      const output = [];
      let match;
      while ((match = regex.exec(text)) !== null) {
        output.push(mapper(match));
        if (output.length >= limit) break;
      }
      regex.lastIndex = 0;
      return output;
    }

    function summarizeJava(filePath, content) {
      const pkg = content.match(/^[ \t]*package\s+([A-Za-z0-9_.]+)\s*;/m)?.[1] || '';
      const imports = uniqueStrings(matchAll(content, /^[ \t]*import\s+([^;]+);/gm, (m) => m[1], 40), 40);
      const annotations = uniqueStrings(matchAll(content, /^[ \t]*@([A-Za-z0-9_.]+)/gm, (m) => m[1], 30), 30);
      const types = matchAll(content, /^[ \t]*(?:public|protected|private)?\s*(?:abstract|final|sealed|non-sealed)?\s*(class|interface|enum|record)\s+([A-Za-z0-9_]+)/gm, (m) => ({ kind: m[1], name: m[2] }), 20);
      const methods = matchAll(content, /^[ \t]*(?:public|protected|private)\s+(?:static\s+)?(?:final\s+)?(?:<[A-Za-z0-9_, ? extends implements]+>\s+)?([A-Za-z0-9_\[\]<>., ?]+)\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[2], returns: m[1].trim(), parameters: String(m[3] || '').trim() }), 40);
      return { path: filePath, language: 'java', package: pkg, imports, annotations, types, methods };
    }

    function summarizePython(filePath, content) {
      const imports = uniqueStrings([
        ...matchAll(content, /^[ \t]*import\s+(.+)$/gm, (m) => m[1], 40),
        ...matchAll(content, /^[ \t]*from\s+(.+)\s+import\s+(.+)$/gm, (m) => 'from ' + m[1] + ' import ' + m[2], 40),
      ], 40);
      const decorators = uniqueStrings(matchAll(content, /^[ \t]*@([A-Za-z0-9_.]+)/gm, (m) => m[1], 30), 30);
      const classes = matchAll(content, /^[ \t]*class\s+([A-Za-z0-9_]+)(?:\(([^\)]*)\))?\s*:/gm, (m) => ({ name: m[1], bases: String(m[2] || '').trim() }), 20);
      const functions = matchAll(content, /^[ \t]*def\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)\s*(?:->\s*([^:]+))?:/gm, (m) => ({ name: m[1], parameters: String(m[2] || '').trim(), returns: String(m[3] || '').trim() }), 40);
      return { path: filePath, language: 'python', imports, decorators, classes, functions };
    }

    function summarizeTsLike(filePath, content, language) {
      const imports = uniqueStrings(matchAll(content, /^[ \t]*import\s+(.+)$/gm, (m) => m[1], 40), 40);
      const exports = uniqueStrings(matchAll(content, /^[ \t]*export\s+(?:default\s+)?(?:class|interface|enum|type|function|const)\s+([A-Za-z0-9_]+)/gm, (m) => m[1], 30), 30);
      const decorators = uniqueStrings(matchAll(content, /^[ \t]*@([A-Za-z0-9_.]+)/gm, (m) => m[1], 30), 30);
      const types = matchAll(content, /^[ \t]*(?:export\s+)?(?:abstract\s+)?(class|interface|enum|type)\s+([A-Za-z0-9_]+)/gm, (m) => ({ kind: m[1], name: m[2] }), 25);
      const functions = matchAll(content, /^[ \t]*(?:export\s+)?(?:async\s+)?function\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[1], parameters: String(m[2] || '').trim() }), 40);
      return { path: filePath, language, imports, decorators, exports, types, functions };
    }

    function summarizeCSharp(filePath, content) {
      const namespaceName = content.match(/^[ \t]*namespace\s+([A-Za-z0-9_.]+)/m)?.[1] || '';
      const usings = uniqueStrings(matchAll(content, /^[ \t]*using\s+([^;]+);/gm, (m) => m[1], 40), 40);
      const attributes = uniqueStrings(matchAll(content, /^[ \t]*\[([A-Za-z0-9_., ()]+)\]/gm, (m) => m[1], 30), 30);
      const types = matchAll(content, /^[ \t]*(?:public|internal|protected|private)?\s*(?:abstract|sealed|partial)?\s*(class|interface|enum|record|struct)\s+([A-Za-z0-9_]+)/gm, (m) => ({ kind: m[1], name: m[2] }), 20);
      const methods = matchAll(content, /^[ \t]*(?:public|protected|private|internal)\s+(?:static\s+)?(?:async\s+)?([A-Za-z0-9_<>,.?\[\] ]+)\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[2], returns: m[1].trim(), parameters: String(m[3] || '').trim() }), 40);
      return { path: filePath, language: 'csharp', namespace: namespaceName, usings, attributes, types, methods };
    }

    function summarizeGo(filePath, content) {
      const pkg = content.match(/^[ \t]*package\s+([A-Za-z0-9_]+)/m)?.[1] || '';
      const imports = uniqueStrings([
        ...matchAll(content, /^[ \t]*import\s+"([^"]+)"/gm, (m) => m[1], 40),
        ...matchAll(content, /^[ \t]*"([^"]+)"$/gm, (m) => m[1], 40),
      ], 40);
      const types = matchAll(content, /^[ \t]*type\s+([A-Za-z0-9_]+)\s+(struct|interface)/gm, (m) => ({ name: m[1], kind: m[2] }), 20);
      const functions = [
        ...matchAll(content, /^[ \t]*func\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[1], receiver: '', parameters: String(m[2] || '').trim() }), 40),
        ...matchAll(content, /^[ \t]*func\s*\(([^\)]*)\)\s*([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[2], receiver: String(m[1] || '').trim(), parameters: String(m[3] || '').trim() }), 40),
      ].slice(0, 40);
      return { path: filePath, language: 'go', package: pkg, imports, types, functions };
    }

    function summarizeGeneric(filePath, content, language) {
      const imports = uniqueStrings([
        ...matchAll(content, /^[ \t]*import\s+(.+)$/gm, (m) => m[1], 20),
        ...matchAll(content, /^[ \t]*using\s+([^;]+);/gm, (m) => m[1], 20),
        ...matchAll(content, /^[ \t]*require\s+['"]([^'"]+)['"]/gm, (m) => m[1], 20),
      ], 30);
      const types = matchAll(content, /^[ \t]*(?:export\s+)?(?:public\s+)?(?:abstract\s+|final\s+|sealed\s+)?(class|interface|enum|record|struct)\s+([A-Za-z0-9_]+)/gm, (m) => ({ kind: m[1], name: m[2] }), 20);
      const functions = matchAll(content, /^[ \t]*(?:export\s+)?(?:async\s+)?(?:function|def|fn)\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm, (m) => ({ name: m[1], parameters: String(m[2] || '').trim() }), 40);
      return { path: filePath, language, imports, types, functions };
    }

    function summarizeImplementationFile(file) {
      const filePath = String(file?.path || '').trim();
      const content = String(file?.content || '');
      const language = detectLanguage(filePath);

      let summary;
      if (language === 'java' || language === 'kotlin') {
        summary = summarizeJava(filePath, content);
      } else if (language === 'python') {
        summary = summarizePython(filePath, content);
      } else if (language === 'typescript' || language === 'tsx' || language === 'javascript' || language === 'jsx') {
        summary = summarizeTsLike(filePath, content, language);
      } else if (language === 'csharp') {
        summary = summarizeCSharp(filePath, content);
      } else if (language === 'go') {
        summary = summarizeGo(filePath, content);
      } else {
        summary = summarizeGeneric(filePath, content, language);
      }

      summary.lineCount = content ? content.replace(/\r\n/g, '\n').split('\n').length : 0;
      return summary;
    }

    return $input.all().map((item) => {
      const json = item.json || {};
      const remainingFiles = Array.isArray(json.remainingFiles) ? json.remainingFiles : [];
      const generatedFilesThisIteration = Array.isArray(json.generatedFilesThisIteration) ? json.generatedFilesThisIteration : [];
      const generatedPaths = new Set(generatedFilesThisIteration.map((file) => String(file.path || '').trim()).filter(Boolean));

      const generatedNoFilesThisIteration = generatedFilesThisIteration.length === 0;

      const nextRemainingFiles = remainingFiles.filter((file) => !generatedPaths.has(String(file.path || '').trim()));
      const previousGeneratedFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
      const previousGeneratedFilePaths = Array.isArray(json.generatedFilePaths) ? json.generatedFilePaths : [];
      const batchSize = Math.max(1, Number(json.batchSize || 15));

      const mergedGeneratedFiles = [
        ...previousGeneratedFiles,
        ...generatedFilesThisIteration,
      ];
      const mergedGeneratedFilePaths = [
        ...previousGeneratedFilePaths,
        ...generatedFilesThisIteration.map((file) => file.path),
      ];

      const generatedImplementationFiles = mergedGeneratedFiles.filter((file) => isImplementationFile(file.path));
      const generatedImplementationIndex = generatedImplementationFiles.map(summarizeImplementationFile);
      const generatedNonImplementationPaths = mergedGeneratedFiles
        .filter((file) => !isImplementationFile(file.path))
        .map((file) => String(file.path || '').trim())
        .filter(Boolean);
      const recentImplementationSummaries = generatedFilesThisIteration
        .filter((file) => isImplementationFile(file.path))
        .map(summarizeImplementationFile);

      const nextCurrentBatchFiles = nextRemainingFiles.slice(0, batchSize);

      return {
        json: {
          ...json,
          generatedFiles: mergedGeneratedFiles,
          generatedFilePaths: mergedGeneratedFilePaths,
          generatedImplementationIndex,
          generatedCodeIndex: generatedImplementationIndex,
          generatedNonImplementationPaths,
          recentImplementationSummaries,
          lastIterationFiles: generatedFilesThisIteration,
          generatedNoFilesThisIteration,
          generatedFileCountTotal: mergedGeneratedFiles.length,
          remainingFiles: nextRemainingFiles,
          remainingFileCount: nextRemainingFiles.length,
          batchSize,
          currentBatchFiles: nextCurrentBatchFiles,
          currentBatchFileCount: nextCurrentBatchFiles.length,
          hasRemainingFiles: nextRemainingFiles.length > 0 ? 'yes' : 'no',
          iteration: Number(json.iteration || 1) + (nextRemainingFiles.length > 0 ? 1 : 0),
        },
        binary: item.binary ?? {},
      };
    });
  }
return beUpdateGenerationState();

function feUpdateRefinementState() {
  function normalizeFiles(value) {
    const files = Array.isArray(value) ? value : [];
    return files.map((entry) => {
      if (typeof entry === 'string') return { path: entry.trim() };
      if (entry && typeof entry === 'object') return { path: String(entry.path ?? '').trim() };
      return { path: '' };
    }).filter((entry) => entry.path);
  }
  function detectLanguage(filePath) {
    const lower = String(filePath || '').toLowerCase();
    if (lower.endsWith('.java')) return 'java';
    if (lower.endsWith('.kt')) return 'kotlin';
    if (lower.endsWith('.py')) return 'python';
    if (lower.endsWith('.ts')) return 'typescript';
    if (lower.endsWith('.tsx')) return 'tsx';
    if (lower.endsWith('.js')) return 'javascript';
    if (lower.endsWith('.jsx')) return 'jsx';
    if (lower.endsWith('.cs')) return 'csharp';
    if (lower.endsWith('.go')) return 'go';
    if (lower.endsWith('.rb')) return 'ruby';
    if (lower.endsWith('.php')) return 'php';
    return 'other';
  }
  function isImplementationFile(filePath) {
    const lower = String(filePath || '').toLowerCase();
    if (!lower.startsWith('frontend/')) return false;
    if (lower.includes('/src/test/') || lower.includes('/tests/') || lower.includes('/test/')) return false;
    if (lower.includes('/resources/') || lower.includes('/db/') || lower.includes('/docs/') || lower.includes('/helm/')) return false;
    if (lower.endsWith('.md') || lower.endsWith('.txt') || lower.endsWith('.yaml') || lower.endsWith('.yml') || lower.endsWith('.xml') || lower.endsWith('.properties') || lower.endsWith('.sql') || lower.endsWith('.json') || lower.endsWith('.csv')) return false;
    return new Set(['java', 'kotlin', 'python', 'typescript', 'tsx', 'javascript', 'jsx', 'csharp', 'go', 'ruby', 'php']).has(detectLanguage(filePath));
  }
  function summarizeFile(file) {
    const filePath = String(file?.path || '').trim();
    const content = String(file?.content || '');
    const language = detectLanguage(filePath);
    const imports = [];
    for (const regex of [/^[ \t]*import\s+([^;\n]+)[;\n]?/gm, /^[ \t]*using\s+([^;\n]+);/gm, /^[ \t]*from\s+([^\n]+)\s+import\s+([^\n]+)/gm]) {
      let match;
      while ((match = regex.exec(content)) !== null && imports.length < 20) imports.push(match.slice(1).filter(Boolean).join(' ').trim());
      regex.lastIndex = 0;
    }
    const types = [];
    let match;
    const typeRegex = /^[ \t]*(?:export\s+)?(?:public\s+|private\s+|protected\s+|internal\s+)?(?:abstract\s+|final\s+|sealed\s+)?(class|interface|enum|record|type|struct)\s+([A-Za-z0-9_]+)/gm;
    while ((match = typeRegex.exec(content)) !== null && types.length < 12) types.push({ kind: match[1], name: match[2] });
    typeRegex.lastIndex = 0;
    const functions = [];
    const fnRegex = /^[ \t]*(?:export\s+)?(?:async\s+)?(?:function|def|func|fn)\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm;
    while ((match = fnRegex.exec(content)) !== null && functions.length < 20) functions.push({ name: match[1], parameters: String(match[2] || '').trim() });
    fnRegex.lastIndex = 0;
    return { path: filePath, language, imports: Array.from(new Set(imports)).slice(0, 20), types, functions, lineCount: content ? content.replace(/\r\n/g, '\n').split('\n').length : 0 };
  }
  return $input.all().map((item) => {
    const json = item.json || {};
    const remainingFiles = Array.isArray(json.remainingFiles) ? json.remainingFiles : [];
    const currentFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const generatedFilesThisIteration = Array.isArray(json.generatedFilesThisIteration) ? json.generatedFilesThisIteration : [];
    const generatedPaths = new Set(generatedFilesThisIteration.map((file) => String(file.path || '').trim()).filter(Boolean));
    const currentMap = new Map(currentFiles.map((file) => [String(file.path || '').trim(), { path: String(file.path || '').trim(), content: file.content }]));
    for (const file of generatedFilesThisIteration) {
      const path = String(file.path || '').trim();
      if (!path) continue;
      currentMap.set(path, { path, content: file.content });
    }
    const nextGeneratedFiles = Array.from(currentMap.values()).sort((a, b) => a.path.localeCompare(b.path));
    const nextRemainingFiles = remainingFiles.filter((file) => !generatedPaths.has(String(file.path || '').trim()));
    const batchSize = Math.max(1, Number(json.batchSize || 4));
    const nextCurrentBatchFiles = nextRemainingFiles.slice(0, batchSize);
    const currentPlanFiles = normalizeFiles(json.currentPlanFiles);
    for (const file of generatedFilesThisIteration) {
      const path = String(file.path || '').trim();
      if (path && !currentPlanFiles.some((entry) => entry.path === path)) currentPlanFiles.push({ path });
    }
    const frontendStructureObject = { files: currentPlanFiles };
    const frontendStructure = JSON.stringify(frontendStructureObject);
    const generatedImplementationIndex = nextGeneratedFiles.filter((file) => isImplementationFile(file.path)).map(summarizeFile);
    const recentImplementationSummaries = generatedFilesThisIteration.filter((file) => isImplementationFile(file.path)).map(summarizeFile);
    return {
      json: {
        ...json,
        generatedFiles: nextGeneratedFiles,
        generatedFilePaths: nextGeneratedFiles.map((file) => file.path),
        generatedFileCountTotal: nextGeneratedFiles.length,
        currentPlanFiles,
        plannedFiles: currentPlanFiles,
        frontendStructure,
        frontendStructureObject,
        remainingFiles: nextRemainingFiles,
        remainingFileCount: nextRemainingFiles.length,
        currentBatchFiles: nextCurrentBatchFiles,
        currentBatchFileCount: nextCurrentBatchFiles.length,
        allPlannedFiles: currentPlanFiles,
        allowedOutputFiles: nextCurrentBatchFiles.map((file) => ({ path: String(file.path || '').trim() })),
        generatedImplementationIndex,
        generatedCodeIndex: generatedImplementationIndex,
        recentImplementationSummaries,
        lastIterationFiles: generatedFilesThisIteration,
        generatedNoFilesThisIteration: generatedFilesThisIteration.length === 0,
        hasRemainingFiles: nextRemainingFiles.length > 0 ? 'yes' : 'no',
        iteration: Number(json.iteration || 1) + (nextRemainingFiles.length > 0 ? 1 : 0),
      },
      binary: item.binary ?? {},
    };
  });
}

return feUpdateRefinementState();

const item = $input.first() ?? { json: {}, binary: {} };
const currentJson = item.json ?? {};
const rawBinary = item.binary ?? {};

function getNodeItemSafe(nodeName) {
  if (typeof $items !== 'function') return null;
  try {
    return ($items(nodeName) || [])[0] || null;
  } catch {
    return null;
  }
}

function cleanJson(source) {
  const json = { ...(source ?? {}) };
  delete json.feedback;
  delete json.Feedback;
  delete json.Approved;
  delete json['Start Again'];
  delete json.reviewMode;
  return json;
}

function cleanBinary(source) {
  return Object.fromEntries(
    Object.entries(source ?? {})
      .filter(([key]) => !/^attachments?(?:_|$)/i.test(String(key)))
      .filter(([key]) => !String(key).endsWith('_firstIteration')),
  );
}

function normalizeFiles(value) {
  const files = Array.isArray(value) ? value : [];
  return files
    .map((entry) => {
      if (typeof entry === 'string') return { path: entry.trim() };
      if (entry && typeof entry === 'object') return { path: String(entry.path ?? '').trim() };
      return { path: '' };
    })
    .filter((entry) => entry.path);
}

const firstNode = getNodeItemSafe('FE - Prepare Information for First Iteration');
const firstJson = cleanJson(firstNode?.json ?? {});
const baseJson = cleanJson(currentJson);
const cleanCurrentBinary = cleanBinary(rawBinary);
const firstFiles = normalizeFiles(firstJson.files).length
  ? normalizeFiles(firstJson.files)
  : normalizeFiles(baseJson.firstIterationFiles);

const outputJson = {
  ...baseJson,
  reviewMode: '',
  firstIterationFiles: firstFiles,
  firstIterationFrontendStructure: String(firstJson.frontendStructure ?? baseJson.firstIterationFrontendStructure ?? '').trim(),
  firstIterationReviewRevisionNumber: Number(firstJson.revisionNumber ?? baseJson.firstIterationReviewRevisionNumber ?? baseJson.revisionNumber ?? 0) || 0,
  firstIterationReviewZipDownloadUrl: String(firstJson.zipDownloadUrl ?? baseJson.firstIterationReviewZipDownloadUrl ?? baseJson.zipDownloadUrl ?? '').trim(),
  firstIterationReviewZipDownloadToken: String(firstJson.zipDownloadToken ?? baseJson.firstIterationReviewZipDownloadToken ?? baseJson.zipDownloadToken ?? '').trim(),
  firstIterationReviewDownloadLinkHtml: String(firstJson.downloadLinkHtml ?? baseJson.firstIterationReviewDownloadLinkHtml ?? baseJson.downloadLinkHtml ?? '').trim(),
};

return [{
  json: outputJson,
  ...(Object.keys(cleanCurrentBinary).length ? { binary: cleanCurrentBinary } : {}),
}];

